$(document).ready(function () {
  let heartbeatTimeline;
  let isPlaying = false;

  function initHeartbeat() {
    heartbeatTimeline = gsap.timeline({ paused: true, repeat: -1 });

    const line1 = document.getElementById('line-1');
    const line2 = document.getElementById('line-2');
    const line1Length = line1.getTotalLength();
    const line2Length = line2.getTotalLength();

    gsap.set('#line-1', {
      strokeDasharray: line1Length,
      strokeDashoffset: line1Length,
    });

    gsap.set('#line-2', {
      strokeDasharray: line2Length,
      strokeDashoffset: line2Length,
    });

    heartbeatTimeline
      .to(
        '#line-1',
        {
          strokeDashoffset: -line1Length * 0.2,
          duration: 0.6,
          ease: 'power1.in',
        },
        0
      )
      .to(
        '#line-1',
        {
          strokeDashoffset: -line1Length * 0.25,
          duration: 0.02,
          ease: 'none',
        },
        0.6
      )
      .to(
        '#line-1',
        {
          strokeDashoffset: -line1Length * 0.45,
          duration: 0.5,
          ease: 'power1.out',
        },
        0.62
      )
      .to(
        '#line-1',
        {
          strokeDashoffset: -line1Length * 0.55,
          duration: 0.02,
          ease: 'none',
        },
        1.12
      )
      .to(
        '#line-1',
        {
          strokeDashoffset: -line1Length * 0.65,
          duration: 0.4,
          ease: 'power1.inOut',
        },
        1.14
      )
      .to(
        '#line-1',
        {
          strokeDashoffset: -line1Length * 0.75,
          duration: 0.02,
          ease: 'none',
        },
        1.54
      )
      .to(
        '#line-1',
        {
          strokeDashoffset: -line1Length,
          duration: 0.7,
          ease: 'power1.out',
        },
        1.56
      )
      .to(
        '#line-2',
        {
          strokeDashoffset: -line2Length * 0.15,
          duration: 0.5,
          ease: 'power1.in',
        },
        0.2
      )
      .to(
        '#line-2',
        {
          strokeDashoffset: -line2Length * 0.35,
          duration: 0.4,
          ease: 'power1.inOut',
        },
        0.7
      )
      .to(
        '#line-2',
        {
          strokeDashoffset: -line2Length * 0.42,
          duration: 0.02,
          ease: 'none',
        },
        1.1
      )
      .to(
        '#line-2',
        {
          strokeDashoffset: -line2Length * 0.58,
          duration: 0.5,
          ease: 'power1.out',
        },
        1.12
      )
      .to(
        '#line-2',
        {
          strokeDashoffset: -line2Length * 0.72,
          duration: 0.03,
          ease: 'none',
        },
        1.62
      )
      .to(
        '#line-2',
        {
          strokeDashoffset: -line2Length * 0.85,
          duration: 0.02,
          ease: 'none',
        },
        1.65
      )
      .to(
        '#line-2',
        {
          strokeDashoffset: -line2Length,
          duration: 0.6,
          ease: 'power1.inOut',
        },
        1.67
      )
      .set(
        '#line-1',
        {
          strokeDashoffset: line1Length,
        },
        2.8
      )
      .set(
        '#line-2',
        {
          strokeDashoffset: line2Length,
        },
        2.8
      );
  }

  heartbeatTimeline.play();

  gsap.to('#axis', {
    strokeDashoffset: -20,
    duration: 1,
    repeat: -1,
    ease: 'none',
  });
});
